arrayPipelines.data:
[
	{
		"$match": {
			"timestamp": {
				"$gte": {{ Math.floor(new Date(start_date.selectedDate).getTime() / 1000) }},
				"$lte": {{ Math.floor(new Date(end_date.selectedDate).getTime() / 1000) }}
			},
			"email": {{ user_id.selectedOptionValue || {"$exists": true} }},
			"environment": {{ env_select.selectedOptionValue || {"$exists": true} }},
			"client_id": {{ client_id.selectedOptionValue || {"$exists": true} }}
		}
	},
	{ "$sort": { "timestamp": -1 } },
	{
		"$project": {
			"_id": 0,
			"Email Date": {
				"$cond": {
					"if": { "$gt": ["$email_date", 0] },
					"then": {
						"$dateToString": {
							"format": "%Y-%m-%d",
							"date": { "$toDate": { "$multiply": ["$email_date", 1] } }
						}
					},
					"else": "N/A"
				}
			},
			"Event Date": {
				"$dateToString": {
					"format": "%Y-%m-%d %H:%M:%S",
					"date": { "$toDate": { "$multiply": ["$timestamp", 1000] } }
				}
			},
			"Event ID": { "$ifNull": ["$sg_event_id", "N/A"] },
			"Event Type": { "$ifNull": ["$event", "N/A"] },
			"Client ID": { "$ifNull": ["$client_id", "N/A"] },
			"Environment": { "$ifNull": ["$environment", "N/A"] },
			"Recipient Email": { "$ifNull": ["$email", "N/A"] },
			"Click URL": { "$ifNull": ["$url", ""] },
			"Workflow Name": { "$ifNull": ["$workflow_name", "N/A"] },
			"Workflow ID": { "$ifNull": ["$workflow_id", "N/A"] },
			"Subject": { "$ifNull": ["$subject", "N/A"] },
			"Template Name": { "$ifNull": ["$template_name", "N/A"] },
			"Message ID": { "$ifNull": ["$sg_message_id", "N/A"] }
		}
	}
]

